// YouTube comment scraper: search top videos, extract comments
const input = $input.first().json;
const keywords = input.keywords || [];
const runId = input.run_id;
const projectId = input.project_id;
const limit = 10;
const results = [];

try {
  // Search YouTube for top videos
  const searchResp = await this.helpers.httpRequest({
    method: 'GET',
    url: `https://www.googleapis.com/youtube/v3/search?part=snippet&q=${encodeURIComponent(keywords.join(' '))}&type=video&order=relevance&publishedAfter=${new Date(Date.now()-7*86400000).toISOString()}&maxResults=5&key=${process.env.YOUTUBE_API_KEY}`,
  });

  const videoIds = (searchResp?.items || []).map(i => i.id.videoId).filter(Boolean);

  // Get comments from top videos
  for (const videoId of videoIds.slice(0, 3)) {
    try {
      const commentsResp = await this.helpers.httpRequest({
        method: 'GET',
        url: `https://www.googleapis.com/youtube/v3/commentThreads?part=snippet&videoId=${videoId}&order=relevance&maxResults=5&key=${process.env.YOUTUBE_API_KEY}`,
      });

      for (const item of (commentsResp?.items || []).slice(0, 4)) {
        const c = item.snippet.topLevelComment.snippet;
        results.push({
          run_id: runId,
          project_id: projectId,
          source: 'youtube',
          raw_text: c.textOriginal || c.textDisplay || '',
          source_url: `https://youtube.com/watch?v=${videoId}`,
          engagement_score: (c.likeCount || 0) + ((item.snippet.totalReplyCount || 0) * 3),
          upvotes: c.likeCount || 0,
          comments: item.snippet.totalReplyCount || 0,
          posted_at: c.publishedAt,
          metadata: { videoId, authorDisplayName: c.authorDisplayName },
        });
      }
    } catch (e) { /* skip video on error */ }
  }
} catch (e) {
  return [{ json: { source: 'youtube', success: false, error: e.message, results: [] } }];
}

// Bulk insert (take top 10 by engagement)
const top10 = results.sort((a,b) => b.engagement_score - a.engagement_score).slice(0, limit);
if (top10.length > 0) {
  await this.helpers.httpRequest({
    method: 'POST',
    url: `${process.env.SUPABASE_URL}/rest/v1/research_results`,
    headers: { 'apikey': process.env.SUPABASE_ANON_KEY, 'Authorization': `Bearer ${process.env.SUPABASE_SERVICE_ROLE_KEY}`, 'Content-Type': 'application/json', 'Prefer': 'return=minimal' },
    body: JSON.stringify(top10),
  });
}

return [{ json: { source: 'youtube', success: true, count: top10.length } }];
